import type {
  Edge,
  EdgeTypes,
  Node,
  NodeTypes,
  ReactFlowProps,
} from "@xyflow/react";

/** Props forwarded to `<ReactFlow />`; canvas owns nodes/edges/types/change handlers. */
export type CanvasReactFlowProps = Omit<
  ReactFlowProps<Node, Edge>,
  | "children"
  | "defaultEdges"
  | "defaultNodes"
  | "edgeTypes"
  | "edges"
  | "nodeTypes"
  | "nodes"
  | "onEdgesChange"
  | "onNodesChange"
>;

export interface CanvasState {
  edges: Edge[];
  nodes: Node[];
}

export interface CanvasActions {
  fitView: () => void;
}

export interface CanvasMeta {
  edgeTypes?: EdgeTypes;
  nodeTypes?: NodeTypes;
  reactFlowProps?: CanvasReactFlowProps;
}

export interface CanvasContextValue {
  actions: CanvasActions;
  meta: CanvasMeta;
  state: CanvasState;
}

import { createContext } from "react";
import type { CanvasContextValue } from "./canvas.types";

export const CanvasContext = createContext<CanvasContextValue | null>(null);

"use client";

import { use } from "react";
import { CanvasContext } from "./canvas.context";

export function useCanvas() {
  const ctx = use(CanvasContext);
  if (!ctx) {
    throw new Error("useCanvas must be used inside Canvas.Root");
  }
  return ctx;
}

"use client";

import type { ReactNode } from "react";
import { useMemo } from "react";
import { CanvasContext } from "./canvas.context";
import type {
  CanvasActions,
  CanvasContextValue,
  CanvasMeta,
  CanvasState,
} from "./canvas.types";

export function CanvasProvider({
  actions,
  children,
  meta,
  state,
}: {
  actions?: Partial<CanvasActions>;
  children: ReactNode;
  meta?: CanvasMeta;
  state: CanvasState;
}) {
  const value = useMemo<CanvasContextValue>(
    () => ({
      actions: {
        fitView: actions?.fitView ?? (() => undefined),
      },
      meta: meta ?? {},
      state,
    }),
    [actions?.fitView, meta, state]
  );

  return <CanvasContext value={value}>{children}</CanvasContext>;
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import { Button } from "../button";

export function CanvasErrorFallback({
  error,
  reset,
  className,
}: {
  error: Error & { digest?: string };
  reset: () => void;
  /** Merged with default layout; omit for full-viewport route errors. */
  className?: string;
}) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-4 p-6 text-center",
        className ?? "h-dvh"
      )}
    >
      <h1 className="font-medium text-lg">Canvas failed to load</h1>
      <p className="max-w-md text-muted-foreground text-sm">{error.message}</p>
      <Button onClick={reset}>Try again</Button>
    </div>
  );
}

.canvas-surface {
  position: absolute;
  inset: 0;
  overflow: hidden;
  background-color: var(--color-canvas-surface);
  background-image: radial-gradient(
    ellipse 83.7% 93.3% at 50% 50%,
    color-mix(in oklab, var(--color-canvas-glow) 22%, transparent) 0%,
    transparent 70%
  );
}

.canvas-surface > .react-flow {
  width: 100%;
  height: 100%;
  background: transparent;
}

.react-flow__pane.draggable,
.react-flow__pane.dragging {
  cursor: default;
}

"use client";

import "@xyflow/react/dist/base.css";
import "@xyflow/react/dist/style.css";
import "./canvas.css";

import {
  addEdge,
  Background,
  BackgroundVariant,
  type OnConnect,
  ReactFlow,
  ReactFlowProvider,
  useEdgesState,
  useNodesState,
} from "@xyflow/react";
import { Provider as JotaiProvider } from "jotai";
import type { ReactNode } from "react";
import { useCallback, useEffect } from "react";
import { CanvasProvider } from "./canvas.provider";
import type { CanvasReactFlowProps } from "./canvas.types";
import { useCanvas } from "./canvas.use";

export interface CanvasFlowProps {
  children?: ReactNode;
}

export interface CanvasRootProps {
  children?: ReactNode;
  meta?: Parameters<typeof CanvasProvider>[0]["meta"];
  state: Parameters<typeof CanvasProvider>[0]["state"];
}

function CanvasFlow({ children }: CanvasFlowProps) {
  const { meta, state } = useCanvas();
  const [nodes, setNodes, onNodesChange] = useNodesState(state.nodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(state.edges);
  const onConnect = meta.reactFlowProps?.onConnect;

  useEffect(() => {
    setNodes(state.nodes);
  }, [setNodes, state.nodes]);

  useEffect(() => {
    setEdges(state.edges);
  }, [setEdges, state.edges]);

  const passThrough: CanvasReactFlowProps = {
    fitView: true,
    maxZoom: 1.2,
    minZoom: 0.2,
    panOnDrag: true,
    panOnScroll: true,
    proOptions: { hideAttribution: true },
    selectNodesOnDrag: false,
    ...meta.reactFlowProps,
  };

  const handleConnect = useCallback<OnConnect>(
    (connection) => {
      setEdges((currentEdges) => addEdge(connection, currentEdges));
      onConnect?.(connection);
    },
    [onConnect, setEdges]
  );

  return (
    <div className="relative h-full min-h-0 w-full min-w-0">
      <div className="canvas-surface">
        <ReactFlow
          {...passThrough}
          edges={edges}
          edgeTypes={meta.edgeTypes}
          nodes={nodes}
          nodeTypes={meta.nodeTypes}
          onConnect={handleConnect}
          onEdgesChange={onEdgesChange}
          onNodesChange={onNodesChange}
        >
          <Background
            color="var(--color-canvas-dot)"
            gap={[32, 41]}
            size={1}
            variant={BackgroundVariant.Dots}
          />
          {children}
        </ReactFlow>
      </div>
    </div>
  );
}

function CanvasRoot({ children, meta, state }: CanvasRootProps) {
  return (
    <CanvasProvider meta={meta} state={state}>
      {children}
    </CanvasProvider>
  );
}

function CanvasSurface({ children }: CanvasFlowProps) {
  return (
    <div className="h-full min-h-0 w-full min-w-0">
      <JotaiProvider>
        <ReactFlowProvider>
          <CanvasFlow>{children}</CanvasFlow>
        </ReactFlowProvider>
      </JotaiProvider>
    </div>
  );
}

export const Canvas = Object.assign(CanvasSurface, {
  Flow: CanvasSurface,
  Root: CanvasRoot,
});

export type CanvasProps = CanvasRootProps;
